import React from 'react';
import ReactDOM from 'react-dom';
import { Book, Config, createApplication, payload, Summary, File, utils } from '@topwrite/common';
import Main from '../components/main';
import * as models from '../models';
import { createHistory } from '@/lib/history';

async function loadLocaleData(locale: string) {
    switch (locale) {
        case 'en':
            return import('../lang/en.json');
        default:
            return import('../lang/zh-CN.json');
    }
}

export default async () => {

    const mountNode = document.getElementById('root');

    payload.set(utils.getPayload());

    const config = Config.createFromObject(payload.get('config', {}));

    let summary = payload.get('summary');

    summary = typeof summary === 'string' ? Summary.createFromText(summary) : Summary.createFromObject(summary);

    createHistory();

    const initialState = {
        book: new Book(payload.get('id'), config, summary),
        file: new File(payload.get('file'))
    };

    const Application = await createApplication(models, initialState, loadLocaleData);

    ReactDOM.render(<Application>
        <Main />
    </Application>, mountNode);
}
