import React, { MouseEvent, PropsWithChildren, useCallback } from 'react';
import { SummaryArticle, useSelector } from '@topwrite/common';
import history from '@/lib/history';

interface LinkProps {
    className?: string
    to: string | SummaryArticle
}

export default function Link({ children, to, className }: PropsWithChildren<LinkProps>) {

    const file = useSelector('file');

    if (to instanceof SummaryArticle) {
        to = to.getPath();
    }

    let href;
    if (to) {
        href = file.relative(to);
    }

    const clickHandler = useCallback((e: MouseEvent<HTMLAnchorElement>) => {
        e.preventDefault();
        history.push(e.currentTarget.href);
    }, []);

    return <a onClick={clickHandler} className={className} href={href}>{children}</a>;
}
